import{_ as l,o as e,c as o,a0 as i}from"./chunks/framework.CSGB4SNl.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"java/eight-legged essay/java-jvmday01.md","filePath":"java/eight-legged essay/java-jvmday01.md"}'),t={name:"java/eight-legged essay/java-jvmday01.md"};function r(n,a,s,d,c,h){return e(),o("div",null,[...a[0]||(a[0]=[i('<h4 id="jvm哪几种情况会产生oom" tabindex="-1">JVM哪几种情况会产生oom <a class="header-anchor" href="#jvm哪几种情况会产生oom" aria-label="Permalink to &quot;JVM哪几种情况会产生oom&quot;">​</a></h4><ol><li>堆：过多对象、栈：深层调用、无限递归、方法区：动态代理生成大量类、直接内存过大、操作系统线程数过多、堆的gc回收效率低回收频繁</li></ol><h4 id="栈和堆的区别是什么" tabindex="-1">栈和堆的区别是什么 <a class="header-anchor" href="#栈和堆的区别是什么" aria-label="Permalink to &quot;栈和堆的区别是什么&quot;">​</a></h4><ol><li>栈：线程私有、用来存放方法调用上下文、局部变量、方法用完就弹出、不用gc去管理其生命周期、引用数据类型的引用在栈中、对象在堆中</li><li>堆：线程共享、new 出来的对象和数组都往这扔、生命周期由gc管理</li><li>如果是成员属性类中的，那么基本和引用所有都在堆中</li></ol><h4 id="了解java中的类加载器吗" tabindex="-1">了解java中的类加载器吗 <a class="header-anchor" href="#了解java中的类加载器吗" aria-label="Permalink to &quot;了解java中的类加载器吗&quot;">​</a></h4><ol><li>类加载器就是在程序运行时动态加载类文件</li><li>加载类：通过本地或网络资源去找到加载.class文件，链接类：验证类的字节码文件、准备分配内存、初始化变量，初始化类：初始化静态代码块和静态成员变量</li><li>流程：加载某个类之前会先去其类加载器中查看是否已经被加载过了，没有则优先委派给父加载器，父加载器无法加载再交由加载器本身去加载，当需要的某个类在某个路径下未找到时，类加载器根据指定的类路径动态加载类</li></ol><h4 id="java中常见的垃圾收集器有哪些" tabindex="-1">java中常见的垃圾收集器有哪些 <a class="header-anchor" href="#java中常见的垃圾收集器有哪些" aria-label="Permalink to &quot;java中常见的垃圾收集器有哪些&quot;">​</a></h4><ol><li>G1 GC-垃圾优先回收器：将堆划分为多个区域，优先收集垃圾最多的那几个区域，适合大内存的应用</li><li>ZGC-Z垃圾回收器：停顿时间非常短、低延迟，非常适合高并发的场景</li><li>并行垃圾回收器：多线程垃圾回收、提高吞吐量</li><li>串行垃圾回收器：单线程执行适合小型应用</li></ol><h4 id="什么条件触发younggc" tabindex="-1">什么条件触发younggc？ <a class="header-anchor" href="#什么条件触发younggc" aria-label="Permalink to &quot;什么条件触发younggc？&quot;">​</a></h4><ol><li>新对象默认往Eden区分配，有Eden、s0、s1区，Eden区满了就自动触发jvm的垃圾回收</li></ol><h4 id="什么时候触发fullgc" tabindex="-1">什么时候触发fullgc？ <a class="header-anchor" href="#什么时候触发fullgc" aria-label="Permalink to &quot;什么时候触发fullgc？&quot;">​</a></h4><ol><li>老年代空间不足、元空间不足、调用System.gc()、年轻代晋升到老年代失败</li></ol>',12)])])}const u=l(t,[["render",r]]);export{g as __pageData,u as default};
